CREATE DATABASE DL_OTO
GO
USE DL_OTO
GO

-- 1. TẠO CẤU TRÚC BẢNG

-- Bảng Hãng Xe
CREATE TABLE HangXe (
    TenHang NVARCHAR(100) PRIMARY KEY,
    QuocGia NVARCHAR(100),
    LogoFullPath NVARCHAR(MAX)
);

-- Bảng Xe (Car)
CREATE TABLE Car (
    Id INT IDENTITY(1,1) PRIMARY KEY,
    TenHang NVARCHAR(100),
    TenDongXe NVARCHAR(200),
    LoaiXe NVARCHAR(100),
    MauSac NVARCHAR(50),
    NamSX INT,
    GiaXe BIGINT,
    HinhAnhFullPath NVARCHAR(MAX),
    MoTa NVARCHAR(MAX),
    SoLuongTon INT,
    CONSTRAINT FK_Car_HangXe FOREIGN KEY (TenHang) REFERENCES HangXe(TenHang) ON DELETE CASCADE
);

-- Bảng Tài Khoản
CREATE TABLE TaiKhoan (
    Username NVARCHAR(50) PRIMARY KEY,
    Password NVARCHAR(100) NOT NULL,
    Role NVARCHAR(20),
    MaNV_MaKH NVARCHAR(20)
);
DROP TABLE TaiKhoan;
GO

CREATE TABLE TaiKhoan (
    Id INT PRIMARY KEY IDENTITY(1,1),
    Username NVARCHAR(100) NOT NULL UNIQUE,
    Password NVARCHAR(255) NOT NULL,
    Role NVARCHAR(20),
    MaNV_MaKH NVARCHAR(20)
);
GO
INSERT INTO TaiKhoan (Username, Password) VALUES ('thanthephong', 'thanthephong');



--Bảng khách hàng 
CREATE TABLE KHACHHANG(
	MaKH UNIQUEIDENTIFIER PRIMARY KEY DEFAULT NEWID(),
    HoTen NVARCHAR(100) NOT NULL,
    GioiTinh NVARCHAR(5) CHECK (GioiTinh IN (N'Nam', N'Nữ')),
    SoDienThoai VARCHAR(15),
    NgaySinh DATE,
    Email NVARCHAR(50)
)
CREATE TABLE NhanVien (
    MaNV INT IDENTITY(1,1) PRIMARY KEY,
    HoTen NVARCHAR(100) NOT NULL,
    NgaySinh DATE,
    GioiTinh NVARCHAR(10),
    ChucVu NVARCHAR(50),
    Luong DECIMAL(18, 2)
);
GO

-- Bảng Đơn Hàng
CREATE TABLE DonHang (
    MaDH UNIQUEIDENTIFIER PRIMARY KEY DEFAULT NEWID(),
    TenDH NVARCHAR(100) NOT NULL,
    MaKhachHang UNIQUEIDENTIFIER NOT NULL,
    MaNV INT,
    NgayLap DATE,
    TongTien BIGINT,
    CONSTRAINT FK_DonHang_KH FOREIGN KEY(MaKhachHang) REFERENCES KhachHang(MaKH),
    CONSTRAINT FK_DonHang_NV FOREIGN KEY(MaNV) REFERENCES NhanVien(MaNV)
);

-- Bảng Chi Tiết Đơn Hàng
CREATE TABLE ChiTietDH (
    MaDH UNIQUEIDENTIFIER NOT NULL,
    MaXe INT NOT NULL,
    NgayLap DATE,
    SoLuong INT,
    CONSTRAINT PK_CTDH PRIMARY KEY(MaDH, MaXe),
    CONSTRAINT FK_CTDH_DH FOREIGN KEY(MaDH) REFERENCES DonHang(MaDH),
    CONSTRAINT FK_CTDH_XE FOREIGN KEY(MaXe) REFERENCES Car(Id)
);
GO
CREATE FUNCTION fn_TinhTongTien(@MaDH UNIQUEIDENTIFIER)
RETURNS BIGINT
AS
BEGIN
    DECLARE @TongTien BIGINT;
    SELECT @TongTien = SUM(ct.SoLuong * c.GiaXe)
    FROM ChiTietDH ct
    JOIN Car c ON ct.MaXe = c.Id
    WHERE ct.MaDH = @MaDH;
    RETURN ISNULL(@TongTien,0);
END;
GO

CREATE TRIGGER trg_UpdateTonKho
ON ChiTietDH
AFTER INSERT
AS
BEGIN
    SET NOCOUNT ON;

    -- Cập nhật tồn kho
    UPDATE c
    SET c.SoLuongTon = c.SoLuongTon - i.SoLuong
    FROM Car c
    JOIN inserted i ON c.Id = i.MaXe;

    -- Kiểm tra tồn kho âm
    IF EXISTS (SELECT 1 FROM Car WHERE SoLuongTon < 0)
    BEGIN
        RAISERROR(N'Số lượng tồn kho không đủ!',16,1);
        ROLLBACK TRANSACTION;
    END
END;
GO


-- Tạo kiểu bảng để truyền danh sách chi tiết xe
CREATE TYPE ChiTietDonHangType AS TABLE
(
    MaXe INT,
    SoLuong INT
);



CREATE PROCEDURE TaoDonHang
    @TenDH NVARCHAR(100),
    @MaKhachHang UNIQUEIDENTIFIER,
    @MaNV INT,
    @NgayLap DATE,
    @ChiTiet ChiTietDonHangType READONLY
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @MaDH UNIQUEIDENTIFIER = NEWID();

    -- Thêm đơn hàng
    INSERT INTO DonHang (MaDH, TenDH, MaKhachHang, MaNV, NgayLap, TongTien)
    VALUES (@MaDH, @TenDH, @MaKhachHang, @MaNV, @NgayLap, 0);

    -- Thêm chi tiết đơn hàng
    INSERT INTO ChiTietDH (MaDH, MaXe, NgayLap, SoLuong)
    SELECT @MaDH, MaXe, @NgayLap, SoLuong
    FROM @ChiTiet;

    -- Cập nhật tổng tiền bằng function
    UPDATE DonHang
    SET TongTien = dbo.fn_TinhTongTien(@MaDH)
    WHERE MaDH = @MaDH;
END;
GO
DECLARE @ChiTiet ChiTietDonHangType;

