CREATE PROCEDURE sp_ThemNhanVien
    @HoTen NVARCHAR(100),
    @NgaySinh DATE,
    @GioiTinh NVARCHAR(10),
    @ChucVu NVARCHAR(50),
    @Luong DECIMAL(18, 2)
AS
BEGIN
    -- Bắt đầu thêm dữ liệu
    INSERT INTO NhanVien (HoTen, NgaySinh, GioiTinh, ChucVu, Luong)
    VALUES (@HoTen, @NgaySinh, @GioiTinh, @ChucVu, @Luong);
    PRINT N'Thêm nhân viên thành công!';
END;
GO

