CREATE VIEW vw_DanhSachNhanVien AS
SELECT 
    MaNV,
    HoTen,
    CONVERT(VARCHAR, NgaySinh, 103) AS NgaySinh, -- Format DD/MM/YYYY
    GioiTinh,
    ChucVu,
    Luong
FROM 
    NhanVien;
GO


