--Procedure khách hàng
CREATE PROC sp_ThemKhachHang
    @HoTen NVARCHAR(100),
    @GioiTinh NVARCHAR(5),
    @SoDienThoai VARCHAR(15),
    @NgaySinh DATE,
    @Email NVARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;

    IF EXISTS (
        SELECT 1
        FROM KHACHHANG
        WHERE SoDienThoai = @SoDienThoai
        AND HoTen = @HoTen
    )
    BEGIN
        RAISERROR (N'Khách hàng đã tồn tại!', 16, 1)
        RETURN
    END

    INSERT INTO KHACHHANG(HoTen, GioiTinh, SoDienThoai, NgaySinh, Email)
    VALUES (@HoTen, @GioiTinh, @SoDienThoai, @NgaySinh, @Email)
END

CREATE PROC sp_SuaKhachHang
    @SoDienThoai VARCHAR(15),
    @HoTen NVARCHAR(100),
    @GioiTinh NVARCHAR(5),
    @NgaySinh DATE,
    @Email NVARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;

    IF NOT EXISTS (SELECT 1 FROM KHACHHANG WHERE SoDienThoai = @SoDienThoai)
    BEGIN
        RAISERROR (N'Không tìm thấy khách hàng!', 16, 1)
        RETURN
    END

    UPDATE KHACHHANG
    SET HoTen = @HoTen,
        GioiTinh = @GioiTinh,
        NgaySinh = @NgaySinh,
        Email = @Email
    WHERE SoDienThoai = @SoDienThoai
END

CREATE PROC sp_XoaKhachHangMKH
    @MaKhachHang  UNIQUEIDENTIFIER
AS
BEGIN
    SET NOCOUNT ON;

    IF NOT EXISTS (
    SELECT 1 FROM
    KHACHHANG Where MaKH=@MaKhachHang
    )
    BEGIN 
        RAISERROR (N'Không tìm thấy khách hàng!', 16, 1)
        RETURN
    END
    DELETE FROM KHACHHANG
    Where MaKH=@MaKhachHang
    PRINT N'Xóa khách hàng thành công!'
END

CREATE PROC sp_XoaKhachHangSDT
    @SoDienThoai VARCHAR(15)
AS
BEGIN
    SET NOCOUNT ON;

    IF NOT EXISTS (
    SELECT 1 FROM
    KHACHHANG Where SoDienThoai=@SoDienThoai
    )
    BEGIN 
        RAISERROR (N'Không tìm thấy khách hàng!', 16, 1)
        RETURN
    END
    DELETE FROM KHACHHANG
    Where SoDienThoai=@SoDienThoai
    PRINT N'Xóa khách hàng thành công!'
END

CREATE PROC sp_TimKhachHangSDT
    @SoDienThoai VARCHAR(15)
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS(
    SELECT *
    FROM KHACHHANG
    WHERE SoDienThoai LIKE '%' + @SoDienThoai + '%')
    BEGIN 
        RAISERROR (N'Không tìm thấy khách hàng!', 16, 1)
        RETURN
    END
    select * FROM KHACHHANG
    WHERE SoDienThoai LIKE '%' + @SoDienThoai + '%' 
    prINT N'TIM THAY KHACH HANG'
END

