--Trigger kiểm tra trùng khách hàng
CREATE TRIGGER trg_KiemTraTrungKH
ON KHACHHANG
AFTER INSERT
AS
BEGIN
    SET NOCOUNT ON;

    IF EXISTS (
        SELECT 1
        FROM KHACHHANG k
        JOIN inserted i
        ON k.SoDienThoai = i.SoDienThoai
        AND k.HoTen = i.HoTen
        GROUP BY k.SoDienThoai, k.HoTen
        HAVING COUNT(*) > 1
    )
    BEGIN
        RAISERROR (N'Khách hàng bị trùng (Tên + SĐT)!', 16, 1)
        ROLLBACK TRANSACTION
    END
END

